messages.content:
Analyze the following JSON PRD and design resource access interfaces.

JSON PRD:
```json
{
  "metadata": {
    "project_name": "Expense Tracker",
    "project_id": "com.example.expense_tracker",
    "version": "1.0.0"
  },
  "functional_requirements": [
    {
      "fr_id": "FR-001",
      "title": "Add Expense",
      "description": "User can add an expense record with amount, category, description, and date. Each record gets a unique ID. Amount must be positive. Date defaults to today. Categories: food, transport, entertainment, shopping, other.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-002",
      "title": "List Expenses",
      "description": "User can list all expense records with optional filtering by category and date range (start_date, end_date). Output includes ID, amount, category, description, date.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-003",
      "title": "Update Expense",
      "description": "User can update an existing expense record by ID. Fields that can be updated: amount, category, description. Check that the record exists.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-004",
      "title": "Delete Expense",
      "description": "User can delete an expense record by ID. Check that the record exists.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-005",
      "title": "Get Summary",
      "description": "User can get expense summary statistics grouped by category or date range. Returns total amount and amounts per category.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    }
  ],
  "non_functional_requirements": [
    {
      "nfr_id": "NFR-001",
      "category": "usability",
      "description": "All operations are performed via a single function call track_expense(command, expense_data)."
    },
    {
      "nfr_id": "NFR-002",
      "category": "reliability",
      "description": "Error handling for invalid ID, negative amount, invalid category."
    }
  ],
  "acceptance_criteria": [
    {
      "ac_id": "AC-001",
      "description": "All 5 operations (add, list, update, delete, summary) execute correctly.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001",
        "FR-002",
        "FR-003",
        "FR-004",
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-002",
      "description": "Filtering by category and date range works correctly.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002"
      ]
    },
    {
      "ac_id": "AC-003",
      "description": "Summary statistics are correct.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-004",
      "description": "Error handling for invalid ID, negative amount, invalid category.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001",
        "FR-003",
        "FR-004"
      ]
    },
    {
      "ac_id": "AC-005",
      "description": "Date range filtering works correctly.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002",
        "FR-005"
      ]
    }
  ],
  "technical_constraints": {
    "storage": {
      "type": "memory",
      "details": "No persistence; data stored in memory during session."
    },
    "concurrency": {
      "model": "single-user",
      "auth_required": false
    },
    "ui": {
      "type": "api"
    },
    "language": "Python"
  },
  "glossary": {
    "expense record": "A single entry containing amount, category, description, date, and unique ID.",
    "category": "One of food, transport, entertainment, shopping, other.",
    "summary": "Aggregated statistics of expenses, optionally grouped by category or date range."
  },
  "global_state_sources": [
    {
      "source_id": "expenses",
      "type": "list",
      "description": "List of all expense records.",
      "initial_state": [],
      "item_schema": {
        "id": "integer",
        "amount": "float",
        "category": "string",
        "description": "string",
        "date": "string (YYYY-MM-DD)"
      }
    },
    {
      "source_id": "next_id",
      "type": "dict",
      "description": "Counter for generating unique expense IDs.",
      "initial_state": {
        "next_id": 1
      },
      "item_schema": {
        "next_id": "integer"
      }
    }
  ],
  "input_spec": {
    "format": "json",
    "description": "Input is provided via the track_expense function with a command string and a JSON object expense_data.",
    "schema": {
      "command": "string (add|list|update|delete|summary)",
      "expense_data": {
        "amount": "float (required for add/update)",
        "category": "string (required for add/update, one of food|transport|entertainment|shopping|other)",
        "description": "string (optional)",
        "date": "string (optional, YYYY-MM-DD, defaults to today)",
        "expense_id": "integer (required for update/delete)",
        "category_filter": "string (optional for list)",
        "start_date": "string (optional for list/summary, YYYY-MM-DD)",
        "end_date": "string (optional for list/summary, YYYY-MM-DD)",
        "group_by": "string (optional for summary, category|date)"
      }
    },
    "examples": [
      {
        "command": "add",
        "expense_data": {
          "amount": 50.0,
          "category": "food",
          "description": "午餐"
        }
      },
      {
        "command": "list",
        "expense_data": {
          "category_filter": "food"
        }
      }
    ]
  },
  "output_spec": {
    "format": "json",
    "description": "Output is a JSON object with success flag, message, and optional data.",
    "schema": {
      "success": "boolean",
      "message": "string",
      "data": "object (varies by operation)"
    },
    "examples": [
      {
        "success": true,
        "message": "记录添加成功，ID=1",
        "data": {
          "expense_id": 1
        }
      },
      {
        "success": true,
        "message": "共1条记录",
        "data": {
          "expenses": [
            {
              "id": 1,
              "amount": 50.0,
              "category": "food",
              "description": "午餐",
              "date": "2024-01-15"
            }
          ],
          "total": 50.0
        }
      }
    ]
  }
}
```

Remember:
- Choose storage model from: dict, list, in_memory_table
- Choose operations from: get, list, create, update, delete, exists
- Do NOT create business action interfaces like pay_order or ship_order
- Create only low-level CRUD interfaces
- Every resource needs at least a get interface
